import React, { useState, useEffect } from 'react';
import { organizations, adminUsers } from '../services/api';
import { useNavigate } from 'react-router-dom';
import './AdminOrganizations.css';

interface Organization {
  id: number;
  name: string;
  created_at: string;
  employee_count?: number;
  document_count?: number;
}

interface User {
  id: number;
  full_name: string;
  login: string;
  role: string;
  organization_id?: number;
  organization_name?: string;
}

const AdminOrganizations: React.FC = () => {
  const navigate = useNavigate();
  const [orgs, setOrgs] = useState<Organization[]>([]);
  const [users, setUsers] = useState<User[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [searchQuery, setSearchQuery] = useState('');
  const [showModal, setShowModal] = useState(false);
  const [editingOrg, setEditingOrg] = useState<Organization | null>(null);
  const [formData, setFormData] = useState({
    name: ''
  });

  useEffect(() => {
    fetchData();
  }, []);

  const fetchData = async () => {
    try {
      setLoading(true);
      const [orgsResponse, usersResponse] = await Promise.all([
        organizations.getAll(),
        adminUsers.getAll()
      ]);

      // Подсчитываем количество сотрудников в каждой организации
      const usersByOrg = usersResponse.data.reduce((acc: any, user: User) => {
        if (user.organization_id) {
          acc[user.organization_id] = (acc[user.organization_id] || 0) + 1;
        }
        return acc;
      }, {});

      const orgsWithCounts = orgsResponse.data.map((org: Organization) => ({
        ...org,
        employee_count: usersByOrg[org.id] || 0
      }));

      setOrgs(orgsWithCounts);
      setUsers(usersResponse.data);
      setError('');
    } catch (error) {
      console.error('Error fetching data:', error);
      setError('Ошибка загрузки данных');
    } finally {
      setLoading(false);
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    try {
      if (editingOrg) {
        await organizations.update(editingOrg.id, formData);
      } else {
        await organizations.create(formData);
      }
      setShowModal(false);
      setEditingOrg(null);
      setFormData({ name: '' });
      fetchData();
    } catch (error) {
      console.error('Error saving organization:', error);
      setError('Ошибка сохранения');
    }
  };

  const handleDelete = async (id: number) => {
    if (!window.confirm('Удалить организацию? Все сотрудники будут откреплены.')) return;
    try {
      await organizations.delete(id);
      fetchData();
    } catch (error) {
      console.error('Error deleting organization:', error);
      setError('Ошибка удаления');
    }
  };

  const handleEdit = (org: Organization) => {
    setEditingOrg(org);
    setFormData({ name: org.name });
    setShowModal(true);
  };

  const filteredOrgs = orgs.filter(org =>
    org.name.toLowerCase().includes(searchQuery.toLowerCase())
  );

  if (loading) {
    return <div className="loading">Загрузка...</div>;
  }

  return (
    <div className="admin-organizations">
      <div className="organizations-header">
        <h1>Управление организациями</h1>
        <button className="add-button" onClick={() => {
          setEditingOrg(null);
          setFormData({ name: '' });
          setShowModal(true);
        }}>
          <i className="fas fa-plus"></i> Добавить организацию
        </button>
      </div>

      {error && <div className="error-message">{error}</div>}

      <div className="organizations-search">
        <i className="fas fa-search"></i>
        <input
          type="text"
          placeholder="Поиск по названию..."
          value={searchQuery}
          onChange={(e) => setSearchQuery(e.target.value)}
        />
      </div>

      <div className="organizations-table-container">
        <table className="organizations-table">
          <thead>
            <tr>
              <th>ID</th>
              <th>Название</th>
              <th>Сотрудников</th>
              <th>Дата создания</th>
              <th>Действия</th>
            </tr>
          </thead>
          <tbody>
            {filteredOrgs.map(org => (
              <tr key={org.id}>
                <td>{org.id}</td>
                <td>{org.name}</td>
                <td>{org.employee_count || 0}</td>
                <td>{new Date(org.created_at).toLocaleDateString()}</td>
                <td className="actions">
                  <button onClick={() => handleEdit(org)} className="edit-btn">
                    <i className="fas fa-edit"></i>
                  </button>
                  <button onClick={() => handleDelete(org.id)} className="delete-btn">
                    <i className="fas fa-trash"></i>
                  </button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      {/* Модальное окно для создания/редактирования */}
      {showModal && (
        <div className="modal">
          <div className="modal-content">
            <h2>{editingOrg ? 'Редактировать' : 'Новая организация'}</h2>
            <form onSubmit={handleSubmit}>
              <div className="form-group">
                <label>Название *</label>
                <input
                  type="text"
                  value={formData.name}
                  onChange={(e) => setFormData({ ...formData, name: e.target.value })}
                  required
                />
              </div>
              <div className="form-actions">
                <button type="submit" className="save-button">
                  {editingOrg ? 'Сохранить' : 'Создать'}
                </button>
                <button type="button" className="cancel-button" onClick={() => setShowModal(false)}>
                  Отмена
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default AdminOrganizations;
